    'privacy__collect_reason_activity2_basis' => 'Base : Requis pour respecter les réglementations contre le blanchiment d’argent. Le 2 facteurs est requis pour garder votre compte sécurisé.',
    'privacy__collect_reason_activity3_title' => 'Activité : Vérification d’identité.',
    'privacy__collect_reason_activity3_info' => 'Informations personnelles : Pièce d’identité officielle, numéro d’identité national.',
    'privacy__collect_reason_activity3_basis' => 'Base : Requis pour respecter les réglementations contre le blanchiment d’argent.',
