    'privacy__collect_reason_creation_text' => 'Vous pouvez créer un profil sur notre site pour acheter et vendre des cryptomonnaies. La base légale est l\'exécution du contrat.',
    'privacy__collect_reason_creation_info_text' => 'Lors de la création d\'un tel profil, nous traitons les informations suivantes :',
    'privacy__collect_reason_creation_list1' => 'Données d\'identification telles que nom, titre, date de naissance et genre.',
    'privacy__collect_reason_creation_list2' => 'Données de contact telles que adresse postale, email et numéro de téléphone.',
    'privacy__collect_reason_creation_list3' => 'Données financières telles que informations de compte bancaire et de carte.',
    'privacy__collect_reason_creation_list4' => 'Données de transaction telles que heure, montant et autres informations sur les transferts entre vous et nous.',
    'privacy__collect_reason_creation_list5' => 'Données de profil telles que nom d\'utilisateur, mot de passe, paramètres et retours sur enquêtes.',
