    'privacy__collect_reason_legal_text' => 'Lors de l\'établissement d\'un profil utilisateur, plusieurs exigences légales doivent être respectées. Voici une description des activités où CapitureX stocke des données personnelles :',
    'privacy__collect_reason_activity1_title' => 'Activité : Création de compte utilisateur.',
