    'privacy__collect_reason_creation_text' => 'You can create a user profile on our website to buy and sell cryptocurrencies. The legal basis for processing is the fulfillment of the agreement.',
    'privacy__collect_reason_creation_info_text' => 'When you create such a profile, we will process the following information:',
